export class Counter {
  constructor(state, env) {
    this.state = state; // Durable Object state
    this.env = env;
  }

  // called when the object gets a request
  async fetch(req) {
    const url = new URL(req.url);
    if (url.pathname === '/increment') {
      let value = (await this.state.storage.get('count')) || 0;
      value += 1;
      await this.state.storage.put('count', value);
      return new Response(String(value));
    }
    const value = (await this.state.storage.get('count')) || 0;
    return new Response(String(value));
  }
}

// Bind a Durable Object in the Workers manifest, then use fetch to the object's stub to interact with it.

