const { v4: uuid } = require('uuid')

class EventStore {
  constructor(){ this.store = new Map() }
  async append(streamId, events){
    const existing = this.store.get(streamId) || []
    this.store.set(streamId, existing.concat(events))
    return true
  }
  async read(streamId){
    return this.store.get(streamId) || []
  }
}

// Create an order
async function placeOrder(eventStore, orderId, items){
  const events = [{ type: 'OrderCreated', data: { id: orderId, timestamp: Date.now() }}]
  items.forEach(it => events.push({ type: 'ItemAdded', data: it }))
  await eventStore.append(orderId, events)
}

// Rebuild state
function applyEvent(state, event){
  switch(event.type){
    case 'OrderCreated': return { ...state, id: event.data.id, items: [], status: 'Created' }
    case 'ItemAdded': return { ...state, items: state.items.concat(event.data) }
    default: return state
  }
}

async function rebuild(eventStore, orderId){
  const events = await eventStore.read(orderId)
  return events.reduce(applyEvent, {})
}
